from concurrent.futures import ThreadPoolExecutor, TimeoutError
import sys

def detect_flakiness(func, n_runs=10, timeout_per_run=5.0):
    try:
        results = []
        EXCEPTION_SENTINEL = object() 

        def run_single_test():
            try:
                # Execute the target function
                return func()
            except Exception:
                # Catch any exception during the test execution
                return EXCEPTION_SENTINEL

        with ThreadPoolExecutor(max_workers=1) as executor:
            # Submit all runs to the executor
            futures = [executor.submit(run_single_test) for _ in range(n_runs)]

            # Collect results with timeout
            for future in futures:
                try:
                    result = future.result(timeout=timeout_per_run)
                    results.append(result)
                except TimeoutError:
                    # Treat timeout as a result, but we'll just append a sentinel for simplicity
                    results.append(EXCEPTION_SENTINEL)
